965" style="height: 18pt;"></td><td colspan="5" class="xl6518965" width="479" style="border-right: 0.5pt solid black; width: 360pt;">기본주당이익</td><td class="xl6818965" width="102" style="border-top: none; border-left: none; width: 77pt;">1.00원</td><td class="xl6418965"></td></tr><tr height="24" style="height: 18pt;"><td height="24" class="xl6418965" style="height: 18pt;"></td><td colspan="5" class="xl6518965" width="479" style="border-right: 0.5pt solid black; width: 360pt;">전환사채</td><td class="xl6818965" width="102" style="border-top: none; border-left: none; width: 77pt;">100</td><td class="xl6418965"></td></tr><tr height="24" style="height: 18pt;"><td height="24" class="xl6418965" style="height: 18pt;"></td><td colspan="6" class="xl7018965" width="581" style="width: 437pt;">전환사채 10개당 보통주 3주로
